import{_ as e,o as a,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"🫘 黃豆追蹤日報 — 2026年5月28日（週四）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-28.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-28.md"}'),n={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-05-28.md"};function i(s,r,l,h,p,d){return a(),t("div",null,[...r[0]||(r[0]=[o('<h1 id="🫘-黃豆追蹤日報-—-2026年5月28日-週四" tabindex="-1">🫘 黃豆追蹤日報 — 2026年5月28日（週四） <a class="header-anchor" href="#🫘-黃豆追蹤日報-—-2026年5月28日-週四" aria-label="Permalink to &quot;🫘 黃豆追蹤日報 — 2026年5月28日（週四）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-28 05:00 = 2026-05-27 21:00 UTC) <strong>昨日敘事延續</strong>：美伊 MOU 框架（1個月恢復100艘/日）→ Trump 否認 → 荷莫茲仍半封鎖 → 化肥價格飆升 90%+ → 但油價大跌 6% 可能緩解部分農業成本壓力</p></blockquote><hr><h2 id="📊-8項指標檢查" tabindex="-1">📊 8項指標檢查 <a class="header-anchor" href="#📊-8項指標檢查" aria-label="Permalink to &quot;📊 8項指標檢查&quot;">​</a></h2><h3 id="指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" tabindex="-1">指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新） <a class="header-anchor" href="#指標1️⃣-usda-種植進度報告-—-🟢-穩定推進-無新更新" aria-label="Permalink to &quot;指標1️⃣ USDA 種植進度報告 — 🟢 穩定推進（無新更新）&quot;">​</a></h3><p>截至 5/24，美國黃豆種植完成度 <strong>79%</strong>（5年平均 53%）。Emergence 49%（5年平均 40%）。Illinois 84%、Iowa 90%。全線超前。本週無新報告（Memorial Day 延後至 5/26 發布，下一份預計 6/2）。</p><p>📎 來源：<a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a> · <a href="https://www.rfdtv.com/crop-progress-highlights-corn-and-soybean-planting-near-completion-as-winter-wheat-concerns-deepen" target="_blank" rel="noreferrer">RFDTV</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-巴西供應-—-🟢-持續擴張" tabindex="-1">指標2️⃣ 巴西供應 — 🟢 持續擴張 <a class="header-anchor" href="#指標2️⃣-巴西供應-—-🟢-持續擴張" aria-label="Permalink to &quot;指標2️⃣ 巴西供應 — 🟢 持續擴張&quot;">​</a></h3><p>巴西收割順利，出口保持強勁。USDA 預測 2026-27 年度全球油籽產量增長。具體最新數據待 CONAB 月度報告。巴西豐收持續壓制國際價格上行空間，但荷莫茲封鎖推高替代航線運費。</p><p>📎 來源：<a href="https://www.farmprogress.com/marketing/soybean-futures-surge-as-usda-forecasts-tighter-supplies" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-尿素價格-多單訊號-—-🔴-劇烈波動-升級" tabindex="-1">指標3️⃣ 尿素價格 + 多單訊號 — 🔴 劇烈波動（升級！） <a class="header-anchor" href="#指標3️⃣-尿素價格-多單訊號-—-🔴-劇烈波動-升級" aria-label="Permalink to &quot;指標3️⃣ 尿素價格 + 多單訊號 — 🔴 劇烈波動（升級！）&quot;">​</a></h3><p><strong>最新報價</strong>：</p><ul><li>埃及尿素：$940/噸（封鎖前約 $490，+92%）</li><li>美國墨西哥灣：$710/噸（2022年以來最高）</li><li>全球肥料價格指數：較去年 +30%，尿素 +60%，DAP +6%</li></ul><p><strong>核心驅動</strong>：荷莫茲海峽承載全球 30%+ 尿素貿易，封鎖導致波斯灣出口中斷。FAO 警告「系統性農糧衝擊」。EU 已暫停氮肥關稅以緩解農民壓力。部分農民轉向使用人類尿素作為替代肥料（FarmProgress 報導）。</p><p>📎 來源：<a href="https://blogs.worldbank.org/en/opendata/fertilizer-prices-surge-as-strait-of-hormuz-disruptions-tighten-" target="_blank" rel="noreferrer">World Bank</a> · <a href="https://www.foodingredientsfirst.com/news/strait-of-hormuz-fertilizer-crisis-food-prices.html" target="_blank" rel="noreferrer">Food Ingredients First</a> · <a href="https://www.farmprogress.com/business/farmers-turn-to-manure-urine-as-fertilizer-prices-surge" target="_blank" rel="noreferrer">Farm Progress</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-荷莫茲海峽通航狀態-—-🔴-重大變動-mou-框架-trump-否認" tabindex="-1">指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 重大變動（MOU 框架 + Trump 否認） <a class="header-anchor" href="#指標4️⃣-荷莫茲海峽通航狀態-—-🔴-重大變動-mou-框架-trump-否認" aria-label="Permalink to &quot;指標4️⃣ 荷莫茲海峽通航狀態 — 🔴 重大變動（MOU 框架 + Trump 否認）&quot;">​</a></h3><p><strong>5/27 最新</strong>：</p><ul><li>伊朗宣佈 MOU 框架：承諾1個月內恢復每日100-120艘通航</li><li><strong>Trump 白宮否認</strong>：稱「完全捏造」，重大問題未解決</li><li>當日實際通航：僅 23 艘（戰前 125-140 艘/日）</li><li>美軍自 4/13 以來已重導 100 艘商船</li><li>伊朗與阿曼共同管理海峽航運（伊朗說法）</li></ul><p><strong>對黃豆影響</strong>：</p><ul><li>若 MOU 落實 → 化肥供應恢復 + 運費正常化 → 黃豆成本下降 5-15%</li><li>若破裂 → 化肥持續短缺 + 運費維持高檔 → 種植成本壓力延續</li><li>當前：市場在「希望」與「否認」之間拉鋸，油價已跌 6% 反映部分和平預期</li></ul><p>📎 來源：<a href="https://www.iranintl.com/en/202605270408" target="_blank" rel="noreferrer">Iran International</a> · <a href="https://www.sahi.com/news/iran-to-restore-100-ship-daily-hormuz-transit-within-1-month-boosting-global-trade-stability-war-PE3_MACR" target="_blank" rel="noreferrer">Sahi</a> · <a href="https://www.cnbcafrica.com/2026/iran-says-draft-deal-with-us-would-reopen-hormuz-shipping-end-naval-blockade" target="_blank" rel="noreferrer">CNBC Africa</a> · <a href="https://reliefweb.int/report/iran-islamic-republic/supply-routes-snapshot-25-may-2026-regional-middle-east-crisis" target="_blank" rel="noreferrer">ReliefWeb</a> （T: 05:00 TST）</p><hr><h3 id="指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距" tabindex="-1">指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距 <a class="header-anchor" href="#指標5️⃣-中美貿易-中國進口-—-🟡-承諾與現實差距" aria-label="Permalink to &quot;指標5️⃣ 中美貿易 + 中國進口 — 🟡 承諾與現實差距&quot;">​</a></h3><ul><li>中國承諾 2026-28 年每年至少購買 2,500 萬噸美國黃豆</li><li>白宮 5/26 事實清單：中國將額外購買每年至少 $170 億美元美國農產品</li><li>2026年前兩個月美國對中黃豆出口 +79.66%</li><li><strong>但</strong>：2025年3月至2026年2月，美國對中農產品出口下降 $149 億（黃豆佔一半），為2007年以來最低</li><li><strong>關鍵問題</strong>：北京可能不願接受超過實際需求的採購要求</li></ul><p>📎 來源：<a href="https://www.scmp.com/economy/global-economy/article/3353803/soybean-counters-scope-china-us-farm-deal-depends-math-analysts-say" target="_blank" rel="noreferrer">SCMP</a> · <a href="https://hpj.com/2026/05/22/china-commits-to-additional-purchases-of-u-s-ag-products/" target="_blank" rel="noreferrer">HPJ</a> · <a href="https://www.forbes.com/sites/kenroberts/2026/04/24/us-soybean-exports-in-2026-show-27-increase-after-abysmal-2025/" target="_blank" rel="noreferrer">Forbes</a> · <a href="https://farmpolicynews.illinois.edu/2026/05/chinas-retaliatory-tariffs-cost-us-ag-exporters-15-billion-study-says/" target="_blank" rel="noreferrer">Farm Policy News</a> （T: 05:00 TST）</p><hr><h3 id="指標6️⃣-天然氣價格-—-🟢-微漲但穩定" tabindex="-1">指標6️⃣ 天然氣價格 — 🟢 微漲但穩定 <a class="header-anchor" href="#指標6️⃣-天然氣價格-—-🟢-微漲但穩定" aria-label="Permalink to &quot;指標6️⃣ 天然氣價格 — 🟢 微漲但穩定&quot;">​</a></h3><ul><li>Henry Hub 現貨：$3.09/MMBtu（+2.75%）</li><li>6月契約均價：~$3.00/MMBtu</li><li>EIA 預測 2026 年平均 $3.64/Mcf</li><li>價格穩定，未見異常波動。天然氣是氮肥生產原料，但目前影響有限。</li></ul><p>📎 來源：<a href="https://tradingeconomics.com/commodity/natural-gas" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://naturalgasintel.com/news/forward-markets-look-past-storage-surplus-as-natural-gas-demand-growth-looms/" target="_blank" rel="noreferrer">Natural Gas Intel</a> （T: 05:00 TST）</p><hr><h3 id="指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-升級為「超級聖嬰」預警" tabindex="-1">指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 升級為「超級聖嬰」預警 <a class="header-anchor" href="#指標7️⃣-聖嬰-拉尼娜氣候風險-—-🔴-升級為「超級聖嬰」預警" aria-label="Permalink to &quot;指標7️⃣ 聖嬰/拉尼娜氣候風險 — 🔴 升級為「超級聖嬰」預警&quot;">​</a></h3><p><strong>重大更新</strong>：全球氣候正從拉尼娜過渡至強聖嬰事件（Super El Niño），預計北半球夏季形成，持續至年底。</p><ul><li><strong>對黃豆影響</strong>：歷史數據顯示聖嬰對全球黃豆單產正面影響 +2%~5%（美國/巴西為主）</li><li><strong>風險</strong>：強聖嬰可能導致南巴西南部洪水 + 巴西北部/東北部乾旱</li><li><strong>2015-16 超級聖嬰</strong>：巴西整體糧食產量 -9.5%</li><li><strong>區域差異</strong>：Ohio 部分地區因暴雨受災，Wisconsin/Michigan 種植延遲，但整體進度仍超前</li></ul><p>📎 來源：<a href="https://wmo.int/resources/publication-series/el-ninola-nina-updates/el-ninola-nina-update-february-2026" target="_blank" rel="noreferrer">WMO</a> · <a href="https://hectar.global/insights/article/el-nino-la-nina-agriculture-how-enso-cycles-reshape-crop-yields-and-commodity-prices-across-5-key-regions" target="_blank" rel="noreferrer">Hectar Global</a> · <a href="https://badgercropnetwork.com/soybean-yield-and-the-2026-super-el-nino-what-growers-need-to-know/" target="_blank" rel="noreferrer">Badger Crop Network</a> · <a href="https://www.cpc.ncep.noaa.gov/products/analysis_monitoring/enso_advisory/ensodisc.shtml" target="_blank" rel="noreferrer">NOAA</a> （T: 05:00 TST）</p><hr><h3 id="指標8️⃣-cbot-黃豆期貨價格區間-—-🔴-小幅下跌至-11-855" tabindex="-1">指標8️⃣ CBOT 黃豆期貨價格區間 — 🔴 小幅下跌至 $11.855 <a class="header-anchor" href="#指標8️⃣-cbot-黃豆期貨價格區間-—-🔴-小幅下跌至-11-855" aria-label="Permalink to &quot;指標8️⃣ CBOT 黃豆期貨價格區間 — 🔴 小幅下跌至 $11.855&quot;">​</a></h3><ul><li><strong>最新報價</strong>：$11.855/bu（5/27，-0.04%）</li><li>月漲幅：+0.70%，年漲 +11.58%</li><li>5/12 WASDE 後曾觸及 $12+/bu 兩年高點，近期回測 $11.90 以下</li><li>12個月預測：~$12.62/bu</li><li><strong>注意</strong>：05:00 TST = 17:00 ET，CME 黃豆期貨處於 14:00-20:00 ET 休息時段，此為前日收盤價</li></ul><p>📎 來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.barchart.com/futures/quotes/ZSK26" target="_blank" rel="noreferrer">Barchart</a> （T: 05:00 TST）</p><hr><h2 id="📰-黃豆即時新聞-5-則" tabindex="-1">📰 黃豆即時新聞 5 則 <a class="header-anchor" href="#📰-黃豆即時新聞-5-則" aria-label="Permalink to &quot;📰 黃豆即時新聞 5 則&quot;">​</a></h2><ol><li><p><strong>[5/27] 伊朗宣佈荷莫茲 MOU：1個月恢復100艘/日 → 油價暴跌 6%</strong> Iran committed to restore 100-120 daily ship transits within a month under draft MOU. Trump dismissed as &quot;fabrication.&quot; Oil prices plunged 6%+. 📎 <a href="https://www.iranintl.com/en/202605270408" target="_blank" rel="noreferrer">Iran International</a> · <a href="https://www.foxnews.com/live-news/iran-irgc-donald-trump-war-nuclear-talks-hormuz-strait-peace-may-27" target="_blank" rel="noreferrer">Fox News</a></p></li><li><p><strong>[5/27] 全球肥料價格飆升：尿素 +60%、埃及尿素 +92%</strong> World Bank reports fertilizer prices surging as Hormuz disruptions tighten supply. Egyptian urea reached $940/ton, US Gulf at $710/ton. 📎 <a href="https://blogs.worldbank.org/en/opendata/fertilizer-prices-surge-as-strait-of-hormuz-disruptions-tighten-" target="_blank" rel="noreferrer">World Bank</a></p></li><li><p><strong>[5/26] 農民轉向尿素替代品：人類尿液肥料崛起</strong> Farmers worldwide turn to manure and human urine as synthetic nitrogen prices surge amid Hormuz crisis. 📎 <a href="https://www.farmprogress.com/business/farmers-turn-to-manure-urine-as-fertilizer-prices-surge" target="_blank" rel="noreferrer">Farm Progress</a></p></li><li><p><strong>[5/26] USDA 作物進度：黃豆 79%、玉米 86%，遠超五年平均</strong> Soybean planting at 79% vs 5-year avg 53%. Illinois 84%, Iowa 90%. Favorable weather aiding completion. 📎 <a href="https://www.dtnpf.com/agriculture/web/ag/news/article/2026/05/26/crop-progress-corn-86-planted-79-26" target="_blank" rel="noreferrer">DTN/PF</a></p></li><li><p><strong>[5/22] 中國承諾加碼購買美國農產品：每年至少 $170 億</strong> White House fact sheet confirms China will buy at least $17B in US ag products annually for 2026-2028, on top of existing 25M tonne soybean commitment. 📎 <a href="https://hpj.com/2026/05/22/china-commits-to-additional-purchases-of-u-s-ag-products/" target="_blank" rel="noreferrer">HPJ</a></p></li></ol><hr><h2 id="🔮-情景分析" tabindex="-1">🔮 情景分析 <a class="header-anchor" href="#🔮-情景分析" aria-label="Permalink to &quot;🔮 情景分析&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>發生機率</th><th>黃豆價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>MOU 簽署 + 海峽1個月內重開</td><td>25%</td><td>-5~10%</td><td>化肥供應恢復 + 運費正常化 + 風險溢價消除</td></tr><tr><td>MOU 簽署但執行緩慢（3-6個月）</td><td>35%</td><td>±0~5%</td><td>市場已部分反映，實際改善需時間</td></tr><tr><td>Trump 否認後談判破裂</td><td>30%</td><td>+10~15%</td><td>化肥持續短缺 + 運費飆升 + 糧食危機升級</td></tr><tr><td>超級聖嬰 + 化肥危機雙重夾擊</td><td>10%</td><td>+15~25%</td><td>全球糧食危機、生物燃料需求激增</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>TradingEconomics (2026-05-27): CBOT Soybeans $11.855/bu</li><li>DTN/PF (2026-05-26): USDA Crop Progress – Soybeans 79%</li><li>World Bank (2026-05): Fertilizer prices surge +30-60%</li><li>Iran International (2026-05-27): Iran MOU 框架</li><li>SCMP (2026-05): China-US soybean trade commitments</li><li>Natural Gas Intel (2026-05-27): Henry Hub $3.09/MMBtu</li><li>WMO/NOAA (2026): El Niño forecast – Super El Niño likely</li><li>Farm Progress (2026-05-27): Farmers turn to alternative fertilizers</li></ol>',50)])])}const g=e(n,[["render",i]]);export{u as __pageData,g as default};
